if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];

const body = $('Webhook').first().json.body || {};

// Load learned weights from DB (falls back to Shipley defaults if not available)
let learnedWeights = { customer_relationship:0.25, technical_solution:0.20, past_performance:0.20, price_competitiveness:0.15, team_composition:0.10, contract_vehicle:0.10 };
try {
  const wRows = $('Load Learned Weights').all().map(i => i.json);
  if (wRows.length > 0) {
    for (const w of wRows) {
      const factor = w.weight_key.replace('pwin.','');
      if (learnedWeights.hasOwnProperty(factor)) learnedWeights[factor] = parseFloat(w.weight_value);
    }
  }
} catch(e) {}

// Pull capture plan context to auto-boost scores where data exists
let capCtx = {};
try { capCtx = $('Fetch Capture Context').first().json || {}; } catch(e) {}
const gateBoost = { 'Gate 1': 0, 'Gate 2': 1, 'Gate 3': 2, 'Gate 4': 3 }[capCtx.gate_stage] || 0;
const hasTeaming = !!(capCtx.teaming_partner && capCtx.teaming_partner.length > 2);
const hasPastPerf = !!(capCtx.past_performance_ref && capCtx.past_performance_ref.length > 2);

// Shipley Pwin weighted scorecard — 6 factors
const weights = learnedWeights;

// Extract scores (1-10 scale)
var scores = {
  customer_relationship: Math.min(10, Math.max(1, Number(body.customer_relationship) || (4 + gateBoost))),
  technical_solution:    Math.min(10, Math.max(1, Number(body.technical_solution) || 5)),
  past_performance:      Math.min(10, Math.max(1, Number(body.past_performance) || (hasPastPerf ? 7 : 4))),
  price_competitiveness: Math.min(10, Math.max(1, Number(body.price_competitiveness) || 5)),
  team_composition:      Math.min(10, Math.max(1, Number(body.team_composition) || (hasTeaming ? 7 : 4))),
  contract_vehicle:      Math.min(10, Math.max(1, Number(body.contract_vehicle) || 5))
};

// Calculate weighted score (0-10 scale)
var weightedScore = 0;
var breakdown = [];
Object.keys(weights).forEach(function(factor) {
  var contribution = scores[factor] * weights[factor];
  weightedScore += contribution;
  breakdown.push({
    factor: factor.replace(/_/g, ' ').replace(/\b\w/g, function(l) { return l.toUpperCase(); }),
    score: scores[factor],
    weight: Math.round(weights[factor] * 100) + '%',
    weighted_contribution: Math.round(contribution * 100) / 100
  });
});

// Convert to Pwin percentage (0-100)
var pwin = Math.round(weightedScore * 10);

// Determine recommendation
var recommendation = 'NO-BID';
var color = 'red';
if (pwin >= 70) { recommendation = 'BID'; color = 'green'; }
else if (pwin >= 50) { recommendation = 'CONDITIONAL BID'; color = 'yellow'; }
else if (pwin >= 35) { recommendation = 'BID WITH TEAMING'; color = 'orange'; }

// Gate review status
var gates = {
  gate_1_pursue: pwin >= 25,
  gate_2_bid: pwin >= 40,
  gate_3_submit: pwin >= 50,
  gate_4_best_final: pwin >= 60
};

var result = {
  status: 'ok',
  action: 'calculate',
  opportunity: body.opportunity || body.target || 'Unknown',
  agency: body.agency || '',
  pwin: pwin,
  weighted_score: Math.round(weightedScore * 100) / 100,
  recommendation: recommendation,
  recommendation_color: color,
  scores: scores,
  breakdown: breakdown,
  gates: gates,
  notes: body.notes || '',
  assessed_by: body.assessed_by || 'GDA Command',
  assessed_at: new Date().toISOString()
};

return [{ json: result }];
